  ('EDS_RF11', 'Financial Literacy & Entrepreneurship Facilitation Roles', 'Groups roles that facilitate livelihood-linked financial literacy, entrepreneurship mentoring and business-skills learning programs.'),
  ('EDS_RF12', 'Corporate Learning & Development Roles', 'Groups internal workforce learning roles focused on organizational upskilling and training impact.'),
  ('EDS_RF13', 'LMS & EdTech Platform Administration Roles', 'Groups roles that administer platform-enabled learning operations and learner activity configuration.'),
  ('EDS_RF14', 'Online & Distance Learning Coordination Roles', 'Groups roles coordinating distributed course operations, learner support and self-paced delivery environments.'),
  ('EDS_RF15', 'Tutoring & Coaching Delivery Roles', 'Groups private tutoring, coaching and academic mentoring roles, with primary ownership assigned to delivery operations.'),
  ('EDS_RF16', 'Assessment Design & Evaluation Roles', 'Groups roles that design, evaluate, review or manage assessments and evaluation quality.'),
  ('EDS_RF17', 'Certification & Credentialing Operations Roles', 'Groups work roles governing certification programs, professional credentials, exam coordination and digital badge evidence. Learners/candidates are excluded as work-role signals.'),
  ('EDS_RF18', 'Test Preparation & Exam Operations Roles', 'Groups exam operations and test-preparation roles where the dominant responsibility relates to assessment readiness and exam lifecycle support.'),
  ('EDS_RF19', 'Language Learning & Assessment Roles', 'Groups language learning, communication training and language assessment roles.'),
  ('EDS_RF20', 'Inclusive & Special Education Support Roles', 'Groups roles supporting neurodiverse, disability and remedial education needs.'),
  ('EDS_RF21', 'Career Guidance & Counseling Roles', 'Groups roles that support career discovery, occupational fit, counseling and learner action planning.'),
  ('EDS_RF22', 'Sports, Arts & Performance Coaching Roles', 'Groups learner-facing coaching and instruction roles in sports, music, arts and performing skills where the primary work pattern is coached skill development.'),
  ('EDS_RF23', 'Education Administration & Infrastructure Roles', 'Groups roles supporting admissions, student lifecycle records, MIS, ERP and institutional infrastructure operations.'),
  ('EDS_RF24', 'Research Operations & Academic Publishing Roles', 'Groups roles supporting academic research coordination, education research analysis, journal operations and publication workflows.'),
  ('EDS_RF25', 'Government & NGO Education Program Roles', 'Groups public education, skilling scheme and social-impact education delivery roles.'),
  ('ES_RF_001', 'IC Design and Physical Implementation', 'Own the RTL blocks, timing paths, floorplans evidence trail, resolve defects within role authority, and hand off decisions with source-backed artifacts.'),
  ('ES_RF_002', 'Pre-Silicon Verification and Validation', 'Own the testbench, coverage, assertions, regressions evidence trail, resolve defects within role authority, and hand off decisions with source-backed artifacts.'),
  ('ES_RF_003', 'Fab Process and Integration Engineering', 'Own the recipes, wafers, SPC charts, process windows evidence trail, resolve defects within role authority, and hand off decisions with source-backed artifacts.'),
  ('ES_RF_004', 'Fab Equipment, Metrology and Yield', 'Own the tool PM records, metrology maps, yield paretos evidence trail, resolve defects within role authority, and hand off decisions with source-backed artifacts.'),
  ('ES_RF_005', 'Package Assembly and Process Engineering', 'Own the bond diagrams, package travellers, assembly yields evidence trail, resolve defects within role authority, and hand off decisions with source-backed artifacts.'),
  ('ES_RF_006', 'Semiconductor Test, Reliability and Quality', 'Own the ATE data, reliability reports, customer qualification packs evidence trail, resolve defects within role authority, and hand off decisions with source-backed artifacts.'),
  ('ES_RF_007', 'Display Process and Module Engineering', 'Own the display panels, module assembly records, yield maps evidence trail, resolve defects within role authority, and hand off decisions with source-backed artifacts.'),
  ('ES_RF_008', 'Optical Test and Product Reliability', 'Own the luminance, color, optical metrology, reliability data evidence trail, resolve defects within role authority, and hand off decisions with source-backed artifacts.'),
  ('ES_RF_009', 'PCB and Component Process Engineering', 'Own the PCB travellers, CAM data, component inspection plans evidence trail, resolve defects within role authority, and hand off decisions with source-backed artifacts.'),
  ('ES_RF_010', 'Supplier and Component Quality', 'Own the IQC reports, MRB records, lot traceability evidence trail, resolve defects within role authority, and hand off decisions with source-backed artifacts.'),
  ('ES_RF_011', 'SMT and PCBA Production Operations', 'Own the SMT programs, PCB loading lists, reflow profiles evidence trail, resolve defects within role authority, and hand off decisions with source-backed artifacts.'),
  ('ES_RF_012', 'PCBA Test, Repair and NPI', 'Own the AOI logs, ICT/FCT results, ECO build package evidence trail, resolve defects within role authority, and hand off decisions with source-backed artifacts.'),
  ('ES_RF_013', 'Finished Device Manufacturing Operations', 'Own the line balance, takt data, production dashboard evidence trail, resolve defects within role authority, and hand off decisions with source-backed artifacts.'),
  ('ES_RF_014', 'Device Quality and Shipment Readiness', 'Own finished-goods test records, final inspection evidence, and packing/export readiness files; resolve defects within role authority and hand off decisions with source-backed artifacts.'),
  ('ES_RF_015', 'Embedded Hardware and Power Electronics Engineering', 'Own the schematics, layouts, firmware interface notes, ECUs evidence trail, resolve defects within role authority, and hand off decisions with source-backed artifacts.'),
  ('ES_RF_016', 'Program and Customer Quality', 'Own validation matrices, ECO status, control-plan evidence, and APQP/PPAP-style gate records; resolve defects within role authority and hand off decisions with source-backed artifacts.'),
  ('GJ_RF_001', 'Diamond Planner', 'Handles rough parcel work by plan sawing, mark yield, flag inclusions. Uses and maintains planning sheet; yield estimate; stone map. Role boundary: Prepare rough-diamond parcel planning inputs including assorting notes, size grouping, yield estimate, sawing or cutting-plan support, risk flags and planning handoff artifacts for review. Cannot independently approve rough valuation, final sawing plan, buyer-grade commitment, parcel release, or commercial acceptance decision.'),
  ('GJ_RF_002', 'Diamond Polishing Supervisor', 'Handles polished diamond packet work by allocate polishing work, control loss, inspect breakage. Uses and maintains daily production sheet; loss record. Role boundary: Supervise polishing work packets, track weight retention, rework status, finish quality, production loss notes and QC handoff for assigned diamonds. Cannot independently release rejected packets, override QC grading, approve abnormal weight loss, change final grade, or authorize buyer dispatch after quality dispute.'),
  ('GJ_RF_003', 'Diamond QC Grader', 'Handles graded diamond work by grade polished stones, trigger rework, release parcel. Uses and maintains grading sheet; rework note. Role boundary: Review grading evidence, record grade observations and flag rework or release readiness. Cannot override certified grade, lab report, treatment disclosure or buyer-approved release decision.'),
  ('GJ_RF_004', 'LGD Growth Technician', 'Handles growth batch work by monitor batch conditions and log growth traceability. Uses and maintains growth log; batch exception note. Role boundary: Maintain LGD growth batch records, monitor assigned process parameters, record equipment readings, flag deviations and prepare batch handoff notes for screening and disclosure review. Cannot independently certify origin, alter growth records, suppress process deviations, approve undisclosed LGD release, or make final HPHT/CVD disclosure decisions.'),
  ('GJ_RF_005', 'LGD CAD and Processing Coordinator', 'Handles LGD jewellery job work by coordinate CAD, polishing and stone use. Uses and maintains CAD file; production handoff. Role boundary: Coordinate LGD CAD or cutting-plan preparation, processing handoff, screening documentation, inscription or report matching, and production status tracking for lab-grown stones. Cannot independently approve final LGD report claims, change inscription or report linkage, bypass screening, or release stones with unresolved origin or disclosure mismatch.'),
  ('GJ_RF_006', 'LGD Disclosure Compliance Coordinator', 'Handles disclosure pack work by verify terminology, screening and buyer disclosure. Uses and maintains disclosure label; buyer certificate pack. Role boundary: Verify LGD disclosure pack, terminology, screening and report-handling completeness. Cannot conceal origin, alter reports or approve unsupported disclosure claims.'),
  ('GJ_RF_007', 'Jewellery CAD Designer', 'Handles CAD model work by translate design brief into manufacturable model. Uses and maintains 3D model; render; metal-weight estimate. Role boundary: Create jewellery CAD models from approved design briefs, maintain version files, estimate size, stone placement and metal weight, and prepare CAD outputs for customer or production review. Cannot independently approve final customer design, guarantee final weight or stone compatibility without review, change approved specifications, or release CAD for production after unresolved mismatch.'),
  ('GJ_RF_008', 'Bench Manufacturing Supervisor', 'Handles cast and set jewellery piece work by supervise casting, setting, soldering and finishing. Uses and maintains job card; rework register. Role boundary: Coordinate bench manufacturing execution across casting, filing, soldering, setting, finishing, job-card updates, material movement and rework tracking for assigned jewellery orders. Cannot independently write off gold loss, accept major casting defects, alter customer-approved design, release defective setting work, or close rework without QC or production approval.'),
  ('GJ_RF_009', 'Jewellery QC Inspector', 'Handles finished jewellery piece work by inspect setting, finishing, dimensions and recovery controls. Uses and maintains QC checklist; dispatch release. Role boundary: Inspect jewellery against job card, finish standards, stone-setting security, weight records, hallmark or HUID documentation where applicable, and dispatch-readiness checklist. Cannot independently override failed QC, alter weight or hallmark records, approve dispatch hold release, or certify purity or HUID compliance without authorized evidence.'),
  ('GJ_RF_010', 'Gemstone Rough Procurement Manager', 'Handles rough gemstone parcel work by buy, assort and bag rough gemstones. Uses and maintains procurement note; parcel ledger. Role boundary: Handle gemstone procurement/cutting/grading artifacts and flag treatment or quality risks. Cannot certify origin, treatment or final grade without authorized gemological approval.'),
  ('GJ_RF_011', 'Gemstone Cutter and Shaper', 'Handles calibrated gemstone work by cut, shape and polish stones to order size. Uses and maintains cutting worksheet; defect note. Role boundary: Handle gemstone procurement/cutting/grading artifacts and flag treatment or quality risks. Cannot certify origin, treatment or final grade without authorized gemological approval.'),
  ('GJ_RF_012', 'Gemstone QC Grader', 'Handles graded gemstone work by grade, flag treatment disclosure and release inventory. Uses and maintains grading note; treatment disclosure. Role boundary: Review grading evidence, record grade observations and flag rework or release readiness. Cannot override certified grade, lab report, treatment disclosure or buyer-approved release decision.'),
  ('GJ_RF_013', 'Jewellery Retail Sales Associate', 'Handles customer requirement and SKU tray work by consult customer, present SKU and record preference. Uses and maintains estimate; customer note. Role boundary: Consult customers, present products, record preferences and hand off valuation/exchange or compliance needs. Cannot finalize old-gold valuation, policy exceptions, high-value compliance approvals or unsupported product claims.'),
  ('GJ_RF_014', 'Retail Inventory Manager', 'Handles SKU tray and stock register work by reconcile stock, tag products and manage transfer. Uses and maintains stock reconciliation; tag log. Role boundary: Maintain stock ledger, SKU movement, tray counts and inventory reconciliation evidence. Cannot conceal stock variance, approve unsupported write-off or override audit findings.'),
  ('GJ_RF_015', 'Jewellery Store Manager', 'Handles store operations and service closure work by own sales floor, cash control, grievance and repair closure. Uses and maintains daily sales report; service closure record. Role boundary: Supervise consultation, stock, billing, repair intake and service closure within store policy. Cannot override regulatory compliance, unsupported valuation, audit findings or high-value exceptions without authority.'),
  ('GJ_RF_016', 'Sample Intake Executive', 'Handles sample packet work by verify sample identity and create intake record. Uses and maintains intake register; sample label. Role boundary: Record sample intake details including customer reference, sample identity, declared weight, packet condition, chain-of-custody movement and assay request documentation. Cannot independently change sample identity or weight record, issue assay result, approve hallmarking, resolve chain-of-custody breach, or override AHC/BIS-related requirements.'),
  ('GJ_RF_017', 'Precious Metal Assayer', 'Handles assay worksheet work by test precious metal content and record result. Uses and maintains assay worksheet; test result. Role boundary: Perform or supervise assay/hallmark documentation under approved controls. Cannot alter purity results, bypass HUID/compliance checks or issue unsupported hallmark claims.'),
  ('GJ_RF_018', 'Hallmarking Quality Manager', 'Handles quality manual and assay report work by approve report issue, handle non-conformance and audit evidence. Uses and maintains assay report; NCR; quality manual. Role boundary: Perform or supervise assay/hallmark documentation under approved controls. Cannot alter purity results, bypass HUID/compliance checks or issue unsupported hallmark claims.'),
  ('GJ_RF_019', 'Gem and Jewellery Merchandiser', 'Handles buyer inquiry and cost sheet work by translate buyer brief into costing and sample plan. Uses and maintains cost sheet; sample tracker. Role boundary: Prepare buyer, costing, shipment and export documentation handoff evidence. Cannot finalize trade finance, customs/legal declarations, sanctions compliance or buyer exceptions without approval.'),
  ('GJ_RF_020', 'Diamond and Jewellery Trader', 'Handles trading parcel work by negotiate parcel terms and record deal boundary. Uses and maintains deal note; parcel memo. Role boundary: Record parcel negotiation, deal note and counterparty handoff evidence. Cannot confirm binding trade or high-value exceptions outside authorization.'),
  ('GJ_RF_021', 'Export Documentation Executive', 'Handles shipment document pack work by prepare invoice, packing list, compliance and shipment tracker. Uses and maintains export invoice; packing list; tracker. Role boundary: Prepare buyer, costing, shipment and export documentation handoff evidence. Cannot finalize trade finance, customs/legal declarations, sanctions compliance or buyer exceptions without approval.'),
  ('GPSC-RF-001', 'Digital Service Business Analysis and Onboarding', 'Supports the analysis, configuration, and onboarding of digital government services onto citizen-facing or internal platforms. This includes mapping service workflows, collecting department requirements, defining form fields, validating service rules, coordinating user onboarding, testing service journeys, and ensuring that citizens or officials can use the service smoothly.'),
  ('GPSC-RF-002', 'GovTech Application, Data and Security Support', 'Supports government technology applications, databases, user access, cybersecurity controls, and platform reliability. This role family works with application tickets, data quality issues, access requests, incident logs, security checks, backups, reports, and coordination between IT, product, security, and department users.'),
  ('GPSC-RF-003', 'Municipal Civic Administration Support', 'Supports day-to-day municipal administration at city, zone, or ward level. This includes handling citizen requests, service records, permits, complaints, field inspection follow-ups, department coordination, public notices, and escalation tracking to ensure civic services are delivered in an organized and accountable manner.'),
  ('GPSC-RF-004', 'Municipal Technical Works and Engineering', 'Supports planning, execution, inspection, and documentation of municipal infrastructure works such as roads, drains, footpaths, buildings, streetlights, and repair projects. This role family handles site measurements, work estimates, contractor coordination, quality checks, progress updates, technical records, and completion documentation.'),
  ('GPSC-RF-005', 'ICCC Operations and Urban Data Monitoring', 'Operates Integrated Command and Control Centre systems used for monitoring city services, incidents, traffic, public safety, environment, utilities, and urban dashboards. This role family supports alert monitoring, incident logging, dashboard checks, CCTV or sensor-based observations, escalation to field teams, and situation reporting.'),
  ('GPSC-RF-006', 'Smart City Project and Vendor Coordination', 'Coordinates smart city projects involving government departments, vendors, system integrators, consultants, and project management teams. This includes tracking milestones, deliverables, approvals, risks, site readiness, installation progress, documentation, issue logs, billing support, and vendor performance follow-up.'),
  ('GPSC-RF-007', 'Metro O&M Technical Roles', 'Supports metro operations and maintenance activities across stations, trains, electrical systems, signalling, tracks, rolling stock, safety systems, and passenger service infrastructure. This role family focuses on equipment readiness, preventive maintenance, fault reporting, service restoration, safety compliance, and reliable metro service delivery.'),
  ('GPSC-RF-008', 'Bus Operations and Depot Management', 'Manages public bus operations and depot-level activities, including fleet dispatch, route scheduling, crew allocation, vehicle readiness, maintenance coordination, charging coordination for e-buses, attendance tracking, fuel or energy records, breakdown response, and passenger service quality.'),
  ('GPSC-RF-009', 'Mobility Fare and Systems Support', 'Supports fare collection and transport technology systems such as ticketing devices, Automated Fare Collection systems, NCMC cards, validators, fleet tracking, passenger information systems, and ITMS platforms. This role family monitors transactions, device uptime, fare accuracy, system alerts, issue resolution, and coordination with technology vendors.'),
  ('GPSC-RF-010', 'Water Supply Utility Engineering', 'Supports engineering and operational activities in urban water supply systems, including pumping stations, storage reservoirs, pipelines, distribution networks, valves, meters, pressure monitoring, leak response, water quality alerts, and service restoration. This role family helps maintain safe, reliable, and accountable water supply delivery.'),
  ('GPSC-RF-011', 'Sewerage, Drainage and Septage Engineering', 'Supports sewerage networks, stormwater drainage systems, sewage pumping stations, treatment coordination, septic tank desludging, overflow response, monsoon preparedness, and field inspections. This role family focuses on public health protection, environmental compliance, drainage reliability, and timely restoration of sanitation services.'),
  ('GPSC-RF-012', 'Sanitation and SWM Field Supervision', 'Supervises field-level sanitation and solid waste management operations, including waste collection routes, source segregation, street sweeping, vehicle movement, transfer points, worker attendance, complaint resolution, hotspot monitoring, and service verification. This role family ensures cleanliness standards are maintained at ward and city levels.'),
  ('GPSC-RF-013', 'Sanitation Compliance and Certification Support', 'Supports sanitation audits, certification processes, cleanliness rankings, inspection documentation, public feedback records, compliance evidence, corrective action tracking, and reporting. This role family connects field sanitation performance with formal certification, regulatory compliance, and citizen perception improvement.'),
  ('GPSC-RF-014', 'Disaster Preparedness and DMEx Coordination Support', 'Supports disaster preparedness activities such as risk mapping, emergency planning, mock drills, resource inventory updates, training coordination, department readiness checks, and Disaster Management Exercise coordination. This role family ensures that response teams, resources, and procedures are prepared before an emergency occurs.'),
  ('GPSC-RF-015', 'Disaster Response Coordination Support', 'Supports real-time emergency and disaster response coordination by tracking incidents, field teams, relief materials, shelters, equipment, rescue support, inter-agency communication, situation reports, and escalation needs. This role family helps ensure that response actions are timely, prioritized, documented, and properly coordinated.'),
  ('GPSC-RF-016', 'Public Procurement Compliance Roles', 'Supports rule-based procurement processes in government and public sector organizations. This includes tender documentation, eligibility checks, bid support, approval routing, purchase records, vendor compliance, audit evidence, contract tracking, and adherence to transparency and financial accountability requirements.'),
  ('GPSC-RF-017', 'GeM Marketplace and Platform Operations', 'Supports procurement activities on the Government e-Marketplace platform, including product or service search, bid creation, vendor comparison, order processing, compliance checks, delivery tracking, invoice support, issue resolution, and procurement record maintenance. This role family ensures platform-based purchasing is accurate, transparent, and compliant.'),
  ('HPS_RF_001', 'Ward Nursing and Inpatient Coordination', 'Track ward assignment, nursing handoff, vitals documentation, medication-order visibility and shift exceptions; escalate clinical changes to the nurse in-charge/doctor without interpreting findings.'),
  ('HPS_RF_002', 'Admission and Bed Management', 'Match admission order, bed class, payer category, isolation need and ward availability; update bed-board status and escalate placement mismatch or delay.'),
  ('HPS_RF_003', 'Discharge and Patient Services Coordination', 'Track discharge summary readiness, pharmacy/billing clearance, follow-up instruction handoff and patient-services queries; escalate missing medical clearance or unresolved payer blockers.'),
  ('HPS_RF_004', 'Medical Records and HIM Operations', 'Index patient records, verify mandatory forms, maintain MRD completeness, support release-of-information tracking and escalate missing or privacy-sensitive documents.'),
  ('HPS_RF_005', 'Hospital Quality and Accreditation Support', 'Collect quality indicators, incident records, audit evidence and corrective-action status; escalate patient-safety gaps or missing accreditation proof to quality leadership.'),
  ('HPS_RF_006', 'Hospital Billing and Insurance Desk', 'Compile billing documents, verify payer requirements, track TPA preauthorization/claim status and escalate rejected documents or patient financial-clearance blockers.'),
  ('HPS_RF_007', 'Clinic Front Office and Patient Intake', 'Capture patient demographics, visit reason, appointment slot, consent and basic intake fields; escalate red-flag symptoms, identity mismatch or missing consent.'),
  ('HPS_RF_008', 'Primary Care Coordination Support', 'Prepare consultation-room readiness, route patients to clinician, update follow-up instructions and referral notes exactly as directed; escalate unresolved clinician instructions.'),
  ('HPS_RF_009', 'Chronic Care Follow-up Support', 'Track chronic-care follow-up dates, preventive reminders, vitals logs and missed appointments; escalate abnormal values or non-adherence risk to clinician/supervisor.'),
  ('HPS_RF_010', 'Clinic Records and Billing Support', 'Maintain clinic visit records, receipts, payment entries and report uploads; escalate billing mismatch, missing records or privacy-sensitive requests.'),
  ('HPS_RF_011', 'OPD Appointment and Queue Coordination', 'Book specialty appointments, manage token/queue status, coordinate waiting-room flow and escalate long delays, urgent symptoms or incorrect doctor routing.'),
  ('HPS_RF_012', 'Specialty Consultation Support', 'Prepare specialty consultation documents, collect prior reports, support scribe-style note capture and route clinician instructions without interpreting clinical findings.'),
  ('HPS_RF_013', 'Referral and Follow-up Coordination', 'Track referral requests, appointment closure, pending reports and follow-up reminders; escalate incomplete referrals, urgent follow-up gaps or report mismatch.'),
  ('HPS_RF_014', 'OPD Billing and Documentation', 'Prepare OPD billing, attach required documents, update payer/category fields and escalate billing disputes or missing service documentation.'),
  ('HPS_RF_015', 'Day-care Procedure Coordination', 'Coordinate procedure slot, patient arrival, doctor/OT-daycare schedule and case-file readiness; escalate schedule conflict or missing clinical order.'),
  ('HPS_RF_016', 'Consent and Pre-procedure Readiness Support', 'Verify consent presence, identity match, pre-procedure checklist completion and required report availability; escalate missing consent or abnormal pre-check flags.'),
  ('HPS_RF_017', 'Post-procedure Discharge Support', 'Track recovery-room documentation, discharge checklist, escort/family handoff and clinician clearance presence without deciding discharge safety.'),
  ('HPS_RF_018', 'Procedure Billing and Clearance', 'Coordinate package estimate, preauthorization, billing clearance and payment status; escalate payer rejection, missing service order or clearance delay.'),
  ('HPS_RF_019', 'Phlebotomy and Sample Collection', 'Verify patient identity, label tubes, document collection time and route specimens; escalate difficult draw, mismatch, missing order or biohazard concern.'),
  ('HPS_RF_020', 'Sample Accessioning and Lab Coordination', 'Create accession IDs, verify sample labels, route samples to correct processing area and document rejection, hold or delay events.'),
  ('HPS_RF_021', 'Laboratory Technical Processing', 'Support assigned test processing documentation, equipment log entries and sample status updates under qualified technical supervision.'),
  ('HPS_RF_022', 'Lab Quality and Critical Value Escalation', 'Track QC exceptions, TAT breaches and critical-value notification attempts; escalate critical alerts to authorized clinical/lab personnel immediately.'),
  ('HPS_RF_023', 'Lab Customer / Report Support', 'Track report readiness, release status, customer queries and corrected-report requests without interpreting results; escalate delayed or critical reports.'),
  ('HPS_RF_024', 'Radiology Front Desk and Scheduling', 'Verify imaging order, modality, patient identity, appointment slot and preparation instructions; escalate wrong order, pregnancy/contrast alert or urgent scheduling issue.'),
  ('HPS_RF_025', 'Radiology Technologist Operations', 'Support modality worklist readiness, patient preparation documentation and supervised scan workflow records without interpreting images or deciding contrast.'),
  ('HPS_RF_026', 'RIS/PACS and Image Workflow Support', 'Track imaging order, modality schedule, image upload, study match, PACS/RIS status and report movement without interpreting image content.'),
  ('HPS_RF_027', 'Radiology Report Coordination', 'Monitor report dictation/transcription/release status, dispatch reports and escalate delayed or urgent reports to radiologist/clinical owner.'),
  ('HPS_RF_028', 'Imaging Safety and Consent Support', 'Collect contrast/MRI safety forms, confirm consent presence and document checklist completion; escalate safety red flags or consent gaps.'),
  ('HPS_RF_029', 'Home Visit Coordination', 'Plan visit schedules, route staff, confirm patient/family availability and escalate visit delay, safety concern or staff mismatch.'),
  ('HPS_RF_030', 'Home Health Aide Support', 'Record ADL support, basic care activities and visit observations under supervision; escalate deterioration, fall risk, unsafe environment or clinical concern.'),
  ('HPS_RF_031', 'Visiting Nurse Coordination', 'Coordinate nurse visit readiness, supplies, clinician instruction visibility and supervision notes; escalate missing orders or patient deterioration.'),
  ('HPS_RF_032', 'Remote Vitals and Family Handoff Support', 'Log remote vitals, confirm family handoff messages and route alerts to supervisor/clinician without clinical interpretation.'),
  ('HPS_RF_033', 'Kit and Equipment Readiness Support', 'Prepare care kits, equipment availability, delivery status and cleaning/return records; escalate missing, damaged or unsafe equipment.'),
  ('HPS_RF_034', 'Teleconsult Intake Coordination', 'Capture patient details, consent status, complaint category, appointment slot and doctor routing; escalate red-flag cues or consent mismatch.'),
  ('HPS_RF_035', 'Consent and Digital Record Support', 'Verify consent capture, upload documents, exchange records and track e-prescription documentation status without giving medical advice.'),
  ('HPS_RF_036', 'Telehealth Platform Operations', 'Track video/call issues, ticket status, provider availability and consultation completion; escalate platform failure or privacy breach.'),
  ('HPS_RF_037', 'Medical Scribe / Consultation Documentation Support', 'Prepare consultation documentation from clinician direction, update EMR notes and route pending items without interpreting or advising.'),
  ('HPS_RF_038', 'Referral and Closure Coordination', 'Track referrals, follow-up appointments, report exchange and consultation closure; escalate non-closure or urgent referral gaps.'),
  ('HPS_RF_039', 'Emergency Call Intake and Dispatch', 'Capture caller details, location, incident category and dispatch instructions exactly as protocol allows; escalate unclear location or clinical-risk cues.'),
  ('HPS_RF_040', 'Ambulance Operations', 'Track ambulance assignment, route movement, fuel/equipment readiness and arrival/departure times; escalate vehicle/equipment unavailability.'),
  ('HPS_RF_041', 'Emergency Medical Technician Support', 'Document EMT-supervised care observations, equipment use and handoff details without owning clinical triage or treatment decisions.'),
  ('HPS_RF_042', 'Hospital Handoff Coordination', 'Coordinate receiving facility notification, ETA, handoff documents and transfer details; escalate delayed acceptance or incomplete handoff.'),
  ('HPS_RF_043', 'Fleet and Response Readiness', 'Check fleet availability, equipment readiness, staffing roster and response readiness metrics; escalate readiness gaps.'),
  ('HPS_RF_044', 'Therapy Appointment and Session Coordination', 'Schedule sessions, confirm therapist availability, track attendance and prepare session records; escalate missed sessions or referral mismatch.'),
  ('HPS_RF_045', 'Physiotherapy Assistance and Exercise Support', 'Support prescribed exercise setup and log completion under therapist direction; escalate pain, dizziness, fall risk or inability to perform exercise.'),
  ('HPS_RF_046', 'Progress Documentation Support', 'Enter session outcomes, progress scores and therapist observations as directed; escalate missing assessments or worsening indicators.'),
  ('HPS_RF_048', 'Equipment and Therapy Space Readiness', 'Prepare therapy space, equipment availability, sanitation and safety checks; escalate faulty equipment or unsafe setup.'),
  ('HPS_RF_049', 'Dental Front Office and Appointment Support', 'Manage dental appointments, patient registration, procedure slot timing and consent reminders; escalate urgent pain, consent gaps or wrong booking.'),
  ('HPS_RF_050', 'Dental Chairside Assistance', 'Prepare chairside materials, update dentist-directed notes and support patient flow under dentist supervision; escalate clinical complications or missing instruments.'),
  ('HPS_RF_051', 'Sterilization and Infection-Control Support', 'Record instrument sterilization cycles, infection-control checklist completion and cleaning status; escalate sterilization breach immediately.'),
  ('HPS_RF_052', 'Dental Imaging and Records Support', 'Coordinate dental x-ray orders, image upload, dental chart updates and records retrieval without interpreting images.'),
  ('HPS_RF_053', 'Dental Billing and Treatment-Plan Coordination', 'Prepare estimates, payment plans and dentist-approved treatment-plan handoff documentation; escalate patient questions requiring clinical advice.'),
  ('HPS_RF_054', 'Confidential Intake and Appointment Coordination', 'Capture appointment requests, consent status and non-clinical intake fields using privacy-safe scripts; escalate any crisis or self-harm language immediately.'),
  ('HPS_RF_055', 'Therapy Session Scheduling Support', 'Coordinate therapist availability, appointment reminders and session attendance without discussing therapy content or advice.'),
  ('HPS_RF_056', 'Record Privacy and Consent Support', 'Maintain consent records, confidentiality flags and access-controlled documents; escalate privacy breach or unauthorized record request.'),
  ('HPS_RF_057', 'Referral and Follow-up Tracking', 'Track referrals, follow-up appointments and closure status without discussing diagnosis or treatment; escalate non-closure or safety-risk cues.'),
  ('HPS_RF_058', 'Risk-Flag Escalation Support', 'Record non-clinical risk flags and route immediately to supervisor/authorized professional without making crisis judgement.'),
  ('HPS_RF_059', 'Antenatal Clinic Coordination', 'Coordinate antenatal appointments, scan/lab follow-up and visit documentation; escalate abnormal flags, missed appointments or privacy issues.'),
  ('HPS_RF_060', 'Fertility Cycle Coordination Support', 'Track fertility cycle milestones, appointment slots, consent documents and lab/scan handoffs under clinician direction; escalate cycle mismatch or consent gap.'),
  ('HPS_RF_061', 'Consent and Privacy Documentation Support', 'Maintain consent forms, privacy-safe records and authorized communication logs; escalate missing consent or unauthorized disclosure risk.'),
  ('HPS_RF_062', 'Scan/Lab Follow-up Coordination', 'Track scan and lab appointments, report receipt and clinician review status without interpreting results; escalate abnormal flags or delayed reports.'),
  ('HPS_RF_063', 'Patient-Support Referral Handoff Support', 'Coordinate patient-support referral handoff appointments and document patient-support requests without providing counselling or advice.'),
  ('HPS_RF_064', 'Dialysis Scheduling and Session Coordination', 'Schedule dialysis sessions, confirm patient arrival, nephrologist instruction visibility and chair/machine allocation; escalate missed session or conflicting instruction.'),
  ('HPS_RF_065', 'Dialysis Technician Operations', 'Support supervised session setup documentation, machine/session readiness checks and workflow records without deciding prescription or settings.'),
  ('HPS_RF_066', 'Vitals and Session Documentation Support', 'Record vitals, session times and nurse/technician notes as directed; escalate abnormal vitals or access-site concerns immediately.'),
  ('HPS_RF_067', 'Infection-Control and Consumables Support', 'Track infection-control checklist, consumables stock and disinfection records; escalate breach, stockout or unsafe reuse risk.'),
  ('HPS_RF_068', 'Chronic Care Follow-up Coordination', 'Coordinate renal follow-up reminders, lab/doctor review dates and chronic-care handoff notes; escalate missed nephrologist review or abnormal flagged report.'),
  ('HPS_RF_069', 'Hospital Pharmacy Dispensing Support', 'Receive prescriptions, support queue preparation, attach billing documentation and route counselling requests to pharmacist.'),
